WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/23.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/23.0/apex.js")} 

records = {!GETRECORDIDS($ObjectType.Contact)};

if (!SetIds(records)) {
 alert('At least 1 item should be selected.');
}

function SetIds(records) {
	var Page = "/apex/JSPresent__CreatePresentationRecord";
	if (records.length > 0) {
		var idList = records.join('~');
		var resultItem = new sforce.SObject("ts2__s_ResultItem__c");
		if (resultItem) {
			resultItem.ts2__sel_contact_id_list__c = idList;
			var createRiResult = sforce.connection.create([resultItem]);
			if (createRiResult && createRiResult[0].getBoolean("success")) {
				var resultId = createRiResult[0].id;
				var url =  Page+"?cId=" + resultId;
				var features = 'directories=no,menubar=no,titlebar=no,toolbar=no,width=600,height=750,scrollbars=true';
				win4 = window.open(url);
				win4.focus();
			}
		}
		return true;
	}
	return false;
}
